impl TryFrom<String> for Host {
    type Error = HostValidationError;
    fn try_from(val: String) -> Result<Self, Self::Error> {
        if val.is_empty() { return Err(HostValidationError::Empty); }
        if val.contains(' ') { return Err(HostValidationError::InvalidCharacters); }
        Ok(Self(val))
    }
}
